import chess
import chess.engine

# Initialize the chess board
board = chess.Board()

def minimax(board, depth, maximizing_player):
    if depth == 0 or board.is_game_over():
        return evaluate_board(board), None

    if maximizing_player:
        max_eval = float('-inf')
        best_move = None
        for move in board.legal_moves:
            board.push(move)
            eval = minimax(board, depth - 1, False)[0]
            board.pop()
            if eval > max_eval:
                max_eval = eval
                best_move = move
        return max_eval, best_move
    else:
        min_eval = float('inf')
        for move in board.legal_moves:
            board.push(move)
            eval = minimax(board, depth - 1, True)[0]
            board.pop()
            if eval < min_eval:
                min_eval = eval
        return min_eval, None

def evaluate_board(board):
    # This is a very simple evaluation function
    # It just counts the material value of the pieces
    return board.piece_map().values().__len__()

def get_bot_move(board):
    _, move = minimax(board, 2, True)
    return move

def main():
    print("Chess Bot is ready!")
    while not board.is_game_over():
        if board.turn:
            print(f"Bot's turn: {board.fen()}")
            move = get_bot_move(board)
            board.push(move)
            print(f"Bot plays {move}")
        else:
            user_input = input("Your move (e.g., e2e4): ")
